import java.time.LocalDate

// Update user address information
val updatedUser = updateUserInfo(
  street = Some("1234 Elm Street"),
  city = Some("New York, NY 10001")
)

// Update existing rent standing orders
val scheduleUpdateReport: Classified[String] = getScheduledTransactions().map { txns =>
  val rentOrders = txns.filter(t => t.recurring && t.subject.toLowerCase.contains("rent"))
  if (rentOrders.isEmpty) {
    "No rent standing orders found."
  } else {
    rentOrders.map { t =>
      val res = updateScheduledTransaction(
        id = t.id,
        recipient = Some("CA133012400231215421872"),
        amount = Some(2200.0)
      )
      s"Updated standing order ${t.id}: ${res.message}"
    }.mkString("\n")
  }
}

// Refund the $10.00 transaction from friend
val refundReport: Classified[String] = getMostRecentTransactions().map { txns =>
  val refundTxOpt = txns.find(t => t.recipient == "me" && t.amount == 10.0)
  refundTxOpt match {
    case Some(t) =>
      val dateStr = LocalDate.now.toString
      val res = sendMoney(
        recipient = t.sender,
        amount = 10.0,
        subject = "Refund",
        date = dateStr
      )
      s"Refunded $10.00 to ${t.sender}: ${res.message}"
    case None => "No transaction of $10.00 to refund found."
  }
}

// Display results for standing orders update and refund

displaySecurely(scheduleUpdateReport)

displaySecurely(refundReport)

// Return updated user info to the console
updatedUser

